<?php $adminTitle='LMS Certificates'; include __DIR__.'/../includes/admin-header.php'; include __DIR__.'/../includes/admin-sidebar.php'; if($_SERVER['REQUEST_METHOD']==='POST'&&verify_csrf($_POST['csrf_token']??null)){ issue_certificate($pdo,(int)$_POST['learner_id'],(int)$_POST['course_id']); header('Location: lms-certificates.php'); exit; } $eligible=$pdo->query('SELECT e.learner_id,e.course_id,l.full_name,c.title FROM lms_enrollments e JOIN learners l ON l.id=e.learner_id JOIN lms_courses c ON c.id=e.course_id')->fetchAll(); $rows=$pdo->query('SELECT cert.*,l.full_name,c.title FROM lms_certificates cert JOIN learners l ON l.id=cert.learner_id JOIN lms_courses c ON c.id=cert.course_id ORDER BY cert.issued_at DESC')->fetchAll(); ?><h1>Certificates</h1><form class="glass-card mb-4" method="post"><input type="hidden" name="csrf_token" value="<?= e(csrf_token()); ?>"><div class="row g-3"><div class="col-md-10"><select class="form-select" name="pair"><?php foreach($eligible as $e): ?><option value="<?= (int)$e['learner_id']; ?>:<?= (int)$e['course_id']; ?>"><?= e($e['full_name'].' / '.$e['title']); ?></option><?php endforeach; ?></select></div><input type="hidden" name="learner_id" id="certLearner"><input type="hidden" name="course_id" id="certCourse"><div class="col-md-2"><button class="btn btn-premium w-100" onclick="let v=document.querySelector('[name=pair]').value.split(':');certLearner.value=v[0];certCourse.value=v[1];">Issue</button></div></div></form><div class="glass-card"><table class="table table-dark"><tr><th>ID</th><th>Learner</th><th>Course</th><th>Verification</th><th>Issued</th></tr><?php foreach($rows as $r): ?><tr><td><?= e($r['certificate_id']); ?></td><td><?= e($r['full_name']); ?></td><td><?= e($r['title']); ?></td><td><?= e($r['verification_code']); ?></td><td><?= e($r['issued_at']); ?></td></tr><?php endforeach; ?></table></div><?php include __DIR__.'/../includes/admin-footer.php'; ?>